'use strict';
(function(){
var scriptEl=document.querySelector('script[src*="recaptcha/api.js"]');
var siteKey=scriptEl?.src.match(/render=([^&]+)/)?.[1];
if(!siteKey||typeof grecaptcha==='undefined'){
return;}
document.querySelectorAll('.recaptcha-token').forEach(function(input){
var form=input.closest('form');
if(!form)return;
var action=input.dataset.action||'submit';
form.addEventListener('submit',function(e){
if(input.value!=='')return;
e.preventDefault();
grecaptcha.ready(function(){
grecaptcha.execute(siteKey,{action:action}).then(function(token){
input.value=token;
form.submit();}).catch(function(){
form.submit();});});});});})();